    /**
     * Scan local network for IoT devices
     */
    public void discoverDevices(String subnet, int port, String discoveryEndpoint,
                                DeviceDiscoveryCallback callback) {
        executorService.submit(() -> {
            int devicesFound = 0;
            ExecutorService scanPool = Executors.newFixedThreadPool(20);

            final int[] foundCount = {0};
            final Object lock = new Object();

            for (int i = 1; i <= 254; i++) {
                final String ip = subnet + "." + i;
                scanPool.submit(() -> {
                    try {
                        String url = "http://" + ip + ":" + port + discoveryEndpoint;
                        IoTResponse response = executeSyncWithUrlConnection(url, "GET", null, null,
                                2000, 3000, false);
                        if (response.isSuccessful()) {
                            synchronized (lock) {
                                foundCount[0]++;
                            }
                            mainHandler.post(() -> callback.onDeviceFound(ip, response));
                        }
                    } catch (Exception e) {
                        // Device not found at this IP - expected for most IPs
                        Log.v(TAG, "No device at " + ip);
                    }
                });
            }

            scanPool.shutdown();
            try {
                scanPool.awaitTermination(60, TimeUnit.SECONDS);
            } catch (InterruptedException e) {
                Log.e(TAG, "Discovery interrupted", e);
            }

            final int total = foundCount[0];
            mainHandler.post(() -> callback.onDiscoveryComplete(total));
        });
    }

