    /**
     * Execute request asynchronously using OkHttp
     */
    public void executeAsync(IoTRequest iotRequest, IoTResponseCallback callback) {
        OkHttpClient client = selectClient(iotRequest);
        Request okRequest = buildOkHttpRequest(iotRequest);

        long startTime = System.currentTimeMillis();

        // Apply custom timeouts if specified
        OkHttpClient requestClient = client;
        if (iotRequest.getConnectTimeoutMs() > 0 || iotRequest.getReadTimeoutMs() > 0) {
            OkHttpClient.Builder builder = client.newBuilder();
            if (iotRequest.getConnectTimeoutMs() > 0) {
                builder.connectTimeout(iotRequest.getConnectTimeoutMs(), TimeUnit.MILLISECONDS);
            }
            if (iotRequest.getReadTimeoutMs() > 0) {
                builder.readTimeout(iotRequest.getReadTimeoutMs(), TimeUnit.MILLISECONDS);
            }
            requestClient = builder.build();
        }

        requestClient.newCall(okRequest).enqueue(new Callback() {
            @Override
            public void onFailure(Call call, IOException e) {
                IoTError.ErrorType errorType = classifyError(e);
                IoTError error = new IoTError(e.getMessage(), -1, e, errorType);
                Log.e(TAG, "Request failed: " + iotRequest.buildFullUrl(), e);
                mainHandler.post(() -> callback.onFailure(error));
            }

            @Override
            public void onResponse(Call call, Response response) throws IOException {
                long elapsed = System.currentTimeMillis() - startTime;
                try {
                    ResponseBody responseBody = response.body();
                    String body = responseBody != null ? responseBody.string() : "";

                    Map<String, String> headers = new HashMap<>();
                    for (String name : response.headers().names()) {
                        headers.put(name, response.header(name));
                    }

                    IoTResponse iotResponse = new IoTResponse(response.code(), body, headers, elapsed);
                    Log.d(TAG, "Response: " + iotResponse);

                    if (response.isSuccessful()) {
                        mainHandler.post(() -> callback.onSuccess(iotResponse));
                    } else {
                        IoTError.ErrorType errorType = response.code() == 401 || response.code() == 403
                                ? IoTError.ErrorType.AUTH_ERROR
                                : IoTError.ErrorType.SERVER_ERROR;
                        IoTError error = new IoTError(
                                "HTTP " + response.code() + ": " + body,
                                response.code(), null, errorType);
                        mainHandler.post(() -> callback.onFailure(error));
                    }
                } finally {
                    response.close();
                }
            }
        });
    }

    /**
     * Execute request synchronously using OkHttp (must be called from background thread)
     */
    public IoTResponse executeSync(IoTRequest iotRequest) throws IOException {
        OkHttpClient client = selectClient(iotRequest);
        Request okRequest = buildOkHttpRequest(iotRequest);

        OkHttpClient requestClient = client;
        if (iotRequest.getConnectTimeoutMs() > 0 || iotRequest.getReadTimeoutMs() > 0) {
            OkHttpClient.Builder builder = client.newBuilder();
            if (iotRequest.getConnectTimeoutMs() > 0) {
                builder.connectTimeout(iotRequest.getConnectTimeoutMs(), TimeUnit.MILLISECONDS);
            }
            if (iotRequest.getReadTimeoutMs() > 0) {
                builder.readTimeout(iotRequest.getReadTimeoutMs(), TimeUnit.MILLISECONDS);
            }
            requestClient = builder.build();
        }

        long startTime = System.currentTimeMillis();
        try (Response response = requestClient.newCall(okRequest).execute()) {
            long elapsed = System.currentTimeMillis() - startTime;
            ResponseBody responseBody = response.body();
            String body = responseBody != null ? responseBody.string() : "";

            Map<String, String> headers = new HashMap<>();
            for (String name : response.headers().names()) {
                headers.put(name, response.header(name));
            }

            return new IoTResponse(response.code(), body, headers, elapsed);
        }
    }

    /**
     * Execute request synchronously using HttpURLConnection (fallback/alternative)
     */
    public IoTResponse executeSyncWithUrlConnection(String urlString, String method, String body,
                                                     Map<String, String> headers,
                                                     int connectTimeout, int readTimeout,
                                                     boolean allowInsecureSsl) throws IOException {
        long startTime = System.currentTimeMillis();
        HttpURLConnection connection = null;

        try {
            URL url = new URL(urlString);
            connection = (HttpURLConnection) url.openConnection();

            // Handle HTTPS with self-signed certs for local devices
            if (allowInsecureSsl && connection instanceof HttpsURLConnection) {
                HttpsURLConnection httpsConnection = (HttpsURLConnection) connection;
                try {
                    SSLContext sslContext = SSLContext.getInstance("TLS");
                    sslContext.init(null, createTrustAllManagers(), new SecureRandom());
                    httpsConnection.setSSLSocketFactory(sslContext.getSocketFactory());
                    httpsConnection.setHostnameVerifier((hostname, session) -> true);
                } catch (NoSuchAlgorithmException | KeyManagementException e) {
                    throw new IOException("SSL setup failed", e);
                }
            }

            connection.setRequestMethod(method);
            connection.setConnectTimeout(connectTimeout);
            connection.setReadTimeout(readTimeout);

            // Set default headers
            for (Map.Entry<String, String> entry : defaultHeaders.entrySet()) {
                connection.setRequestProperty(entry.getKey(), entry.getValue());
            }

            // Set custom headers
            if (headers != null) {
                for (Map.Entry<String, String> entry : headers.entrySet()) {
                    connection.setRequestProperty(entry.getKey(), entry.getValue());
                }
            }

            // Set auth token for cloud requests
            if (authToken != null && !isLocalAddress(urlString)) {
                connection.setRequestProperty("Authorization", "Bearer " + authToken);
            }

            // Write body
            if (body != null && !body.isEmpty()) {
                connection.setDoOutput(true);
                connection.setRequestProperty("Content-Type", "application/json; charset=utf-8");
                try (OutputStream os = connection.getOutputStream()) {
                    os.write(body.getBytes("UTF-8"));
                    os.flush();
                }
            }

            // Read response
            int statusCode = connection.getResponseCode();
            StringBuilder responseBody = new StringBuilder();

            try (BufferedReader reader = new BufferedReader(new InputStreamReader(
                    statusCode >= 400 ? connection.getErrorStream() : connection.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    responseBody.append(line);
                }
            } catch (Exception e) {
                // Some error streams may be null
                Log.w(TAG, "Could not read response body", e);
            }

            Map<String, String> responseHeaders = new HashMap<>();
            for (Map.Entry<String, java.util.List<String>> entry : connection.getHeaderFields().entrySet()) {
                if (entry.getKey() != null && entry.getValue() != null && !entry.getValue().isEmpty()) {
                    responseHeaders.put(entry.getKey(), entry.getValue().get(0));
                }
            }

            long elapsed = System.currentTimeMillis() - startTime;
            return new IoTResponse(statusCode, responseBody.toString(), responseHeaders, elapsed);

        } finally {
            if (connection != null) {
                connection.disconnect();
            }
        }
    }

    /**
     * Execute using HttpURLConnection asynchronously
     */
    public void executeAsyncWithUrlConnection(String urlString, String method, String body,
                                               Map<String, String> headers,
                                               int connectTimeout, int readTimeout,
                                               boolean allowInsecureSsl,
                                               IoTResponseCallback callback) {
        executorService.submit(() -> {
            try {
                IoTResponse response = executeSyncWithUrlConnection(
                        urlString, method, body, headers, connectTimeout, readTimeout, allowInsecureSsl);
                if (response.isSuccessful()) {
                    mainHandler.post(() -> callback.onSuccess(response));
                } else {
                    IoTError.ErrorType errorType = response.getStatusCode() == 401 || response.getStatusCode() == 403
                            ? IoTError.ErrorType.AUTH_ERROR
                            : IoTError.ErrorType.SERVER_ERROR;
                    IoTError error = new IoTError(
                            "HTTP " + response.getStatusCode() + ": " + response.getBody(),
                            response.getStatusCode(), null, errorType);
                    mainHandler.post(() -> callback.onFailure(error));
                }
            } catch (Exception e) {
                IoTError.ErrorType errorType = classifyError(e);
                IoTError error = new IoTError(e.getMessage(), -1, e, errorType);
                mainHandler.post(() -> callback.onFailure(error));
            }
        });
    }

